template<typename T>
void verify(const T* cpu_out, const T* gpu_out, int64_t n)
{
  int error = memcmp(cpu_out, gpu_out, n * sizeof(T));
  if (error) {
    for (int64_t i = 0; i < n; i++) {
      if (cpu_out[i] != gpu_out[i]) {
        printf("@%zu: %lf != %lf\n", i, (double)cpu_out[i], (double)gpu_out[i]);
        break;
      }
    }
  }
  printf("%s\n", error ? "FAIL" : "PASS");
}

#define LOG_MEM_BANKS 5
#define OFFSET(n) ((n) >> LOG_MEM_BANKS)

template<typename T, int N>
void scan_bcao_impl(
  const int64_t nblocks,
  T *g_odata,
  const T *g_idata)
{
  T temp[2*N];

  #pragma omp parallel for
  for (int64_t bid = 0; bid < nblocks; bid++)
  {
    auto gi = g_idata + bid * N;
    auto go = g_odata + bid * N;

    int thid = 0; // Simulating single thread per block logic sequentially
    int a = thid;
    int b = a + (N/2);
    int oa = OFFSET(a);
    int ob = OFFSET(b);

    // Since we are sequential per block, we just process the whole block
    // The original CUDA code iterates over threads. 
    // We need to simulate the parallel thread behavior sequentially for correctness.

    // Initialize temp for this block
    for(int t=0; t<N; t++) {
        int oa_t = OFFSET(t);
        temp[t + oa_t] = gi[t];
    }
    // Handle the second half if N is even (which it is in usage)
    // The original code: temp[a + oa] = gi[a]; temp[b + ob] = gi[b]; where b = a + N/2
    // This covers all elements when run by all threads. 
    // In sequential simulation:
    for(int t=0; t<N/2; t++) {
        int a_idx = t;
        int b_idx = t + N/2;
        int oa_a = OFFSET(a_idx);
        int oa_b = OFFSET(b_idx);
        temp[a_idx + oa_a] = gi[a_idx];
        temp[b_idx + oa_b] = gi[b_idx];
    }

    int offset = 1;
    for (int d = N >> 1; d > 0; d >>= 1)
    {
      if (0 < d) // thid < d condition for thid=0 is always true if d>0, but we need to simulate all threads
      {
        // Simulate all threads for this step
        for(int thid_sim = 0; thid_sim < d; thid_sim++) {
          int ai = offset*(2*thid_sim+1)-1;
          int bi = offset*(2*thid_sim+2)-1;
          ai += OFFSET(ai);
          bi += OFFSET(bi);
          temp[bi] += temp[ai];
        }
      }
      offset *= 2;
    }

    temp[N-1+OFFSET(N-1)] = 0; 

    for (int d = 1; d < N; d *= 2) 
    {
      offset >>= 1;
      if (0 < d)
      {
        for(int thid_sim = 0; thid_sim < d; thid_sim++) {
          int ai = offset*(2*thid_sim+1)-1;
          int bi = offset*(2*thid_sim+2)-1;
          ai += OFFSET(ai);
          bi += OFFSET(bi);
          T t_val = temp[ai];
          temp[ai] = temp[bi];
          temp[bi] += t_val;
        }
      }
    }

    for(int t=0; t<N; t++) {
        int oa_t = OFFSET(t);
        go[t] = temp[t + oa_t];
    }
  }
}

